import './App.css';
import { useState } from 'react';

function App() {

  const [todo, setTodo] = useState([])
  const [isDarkMode, setisDarkMode] = useState(false)
  const toggleDarkMode = () => {
    setisDarkMode(!isDarkMode)

  }

  const handleAdd = () => {
    const newTodo = document.getElementById("input").value
    if (!newTodo.trim()) return; //prevents empty todos
    document.getElementById("input").value = "";
    setTodo(td => {
      return [...td, { text: newTodo, completed: false }];
    });
  }

  const handleEdit = () => {

  }

  const toggleComplete = (index) => {
    setTodo(prev =>
      prev.map((t, i) => (i === index ? { ...t, completed: !t.completed } : t))
    )
  }

  const handleDelete = (index) => {
    setTodo(todo.filter((_, i) => i !== index));
  }

  return (
    <div className={`app ${isDarkMode ? 'dark' : 'light'}`}>
      <div className='wrap'>
        <h1 className='logo'>ToDo LIST</h1>
        <div className='add-tasks'>
          <input
            id='input'
            type='text'
            placeholder='Add your tasks...'
          />
          <button className='add' onClick={handleAdd}>ADD</button>
          <button className='mode' onClick={toggleDarkMode}>{isDarkMode ? "☀️" : "🌙"}</button>
        </div>
      </div>

      <div className='tasks'>
        <h2>Goals to Achieve</h2>
        {todo.map((items, index) => (
          <div className='list-wrapper' key={index}>
            <input type='checkbox' onChange={() => toggleComplete(index)}/>
            <div className='list'>
              <span style={{ textDecoration: items.completed ? "line-through" : "none" }}>
                {items.text}</span>
              <div>
                <button onClick={() => handleEdit(index)}>Edit</button>
                <button onClick={() => handleDelete(index)}>Delete</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}

export default App;
